import java.io.IOException;
import java.io.PrintWriter;
import javax.servlet.http.*;

public class XssSecureServlet extends HttpServlet {
    protected void doPost(HttpServletRequest request, HttpServletResponse response) throws IOException {
        response.setContentType("text/html");
        PrintWriter out = response.getWriter();

        String userInput = request.getParameter("input");
        String encodedUserInput = encodeForHtml(userInput);

        out.println("<html>");
        out.println("<body>");
        out.println("<h2>User Input:</h2>");
        out.println(encodedUserInput); // This line is now secure against XSS
        out.println("</body>");
        out.println("</html>");
    }

    private String encodeForHtml(String input) {
        return input.replace("&", "&amp;")
                    .replace("<", "&lt;")
                    .replace(">", "&gt;")
                    .replace("\"", "&quot;")
                    .replace("'", "&#39;");
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
